To prevent Cross-Site Scripting (XSS) attacks, you should properly sanitize and encode user input before displaying it in the HTML response. Here's an improved version of the code snippet that addresses the XSS vulnerability:

```java
import java.io.IOException;
import java.io.PrintWriter;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XSSSafeServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");

        // Sanitize and encode user input to prevent XSS
        String safeUserInput = sanitizeInput(userInput);

        out.println("<h1>Hello, " + safeUserInput + "!</h1>");

        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeInput(String input) {
        // Perform proper input sanitization here (e.g., using OWASP ESAPI library)
        // For simplicity, this example just replaces "<" and ">" characters with their HTML entities
        return input.replaceAll("<", "&lt;").replaceAll(">", "&gt;");
    }
}

